query.sparql:
SELECT ?person ?personLabel WHERE {
  wd:Q761383 wdt:P138 ?person.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?character WHERE {
  ?character wdt:P451 wd:Q4205826.
  ?character wdt:P451 wd:Q4463198.
}

SELECT ?founder ?founderLabel WHERE {
  ?company wdt:P31 wd:Q22785;
           wdt:P10786 ?dateOfIncorporation;
           wdt:P102 ?politicalParty.
  ?founder wdt:P31 wd:Q2422932;
           wdt:P199 ?company;
           wdt:P102 wd:Q100200;  # National People's Congress
           rdfs:label ?founderLabel.
  FILTER(LANG(?founderLabel) = "en")
}

SELECT ?work ?workLabel WHERE {
  ?author wdt:P50 wd:Q100000;  # Hunter x Hunter author
          wdt:P9687 ?authorGivenNames.
  ?work wdt:P50 ?author;
        wdt:P1433 ?publication.
  ?publication wdt:P2679 ?forewordAuthor.
  FILTER(CONTAINS(LCASE(?workLabel), "middle school student"))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work ?workLabel WHERE {
  ?work wdt:P50 ?author .
  ?author wdt:P31 wd:Q9379 .  # instance of human
  FILTER NOT EXISTS { ?work wdt:P6333 wd:Q123456 }  # replace Q123456 with the witcher series identifier
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?state WHERE {
  {
    wd:Q10420480 wdt:P276 ?state.
  } UNION {
    wd:Q10420481 wdt:P276 ?state.
  }
}
